import logging
import json
import azure.functions as func


def main(req: func.HttpRequest) -> func.HttpResponse:
    """
    Azure Function HTTP API endpoint for a single-page application.
    Handles CORS preflight requests and regular API requests.
    """
    logging.info('Python HTTP trigger function processed a request.')

    # Define CORS headers - allow all origins for development flexibility
    cors_headers = {
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, PATCH, OPTIONS",
        "Access-Control-Allow-Headers": "Content-Type, Authorization, X-Requested-With, Accept, Origin",
        "Access-Control-Max-Age": "86400",
        "Access-Control-Expose-Headers": "Content-Length, X-Request-Id"
    }

    # Handle CORS preflight (OPTIONS) requests
    if req.method == "OPTIONS":
        return func.HttpResponse(
            status_code=204,
            headers=cors_headers
        )

    # Route handling based on the 'action' route parameter or query parameter
    action = req.route_params.get('action', '') or req.params.get('action', '')

    try:
        if req.method == "GET":
            response_data = handle_get(req, action)
        elif req.method == "POST":
            response_data = handle_post(req, action)
        elif req.method == "PUT":
            response_data = handle_put(req, action)
        elif req.method == "DELETE":
            response_data = handle_delete(req, action)
        else:
            response_data = {
                "status": "error",
                "message": f"Unsupported HTTP method: {req.method}"
            }
            return func.HttpResponse(
                json.dumps(response_data),
                status_code=405,
                mimetype="application/json",
                headers=cors_headers
            )

        return func.HttpResponse(
            json.dumps(response_data),
            status_code=200,
            mimetype="application/json",
            headers=cors_headers
        )

    except ValueError as ve:
        logging.error(f"Validation error: {str(ve)}")
        error_response = {
            "status": "error",
            "message": str(ve)
        }
        return func.HttpResponse(
            json.dumps(error_response),
            status_code=400,
            mimetype="application/json",
            headers=cors_headers
        )

    except Exception as e:
        logging.error(f"Internal server error: {str(e)}")
        error_response = {
            "status": "error",
            "message": "Internal server error",
            "detail": str(e)
        }
        return func.HttpResponse(
            json.dumps(error_response),
            status_code=500,
            mimetype="application/json",
            headers=cors_headers
        )


def handle_get(req: func.HttpRequest, action: str) -> dict:
    """Handle GET requests."""
    logging.info(f"Handling GET request for action: {action}")

    if action == "health":
        return {
            "status": "healthy",
            "message": "API is running"
        }

    if action == "items":
        # Example: return a list of items
        items = [
            {"id": 1, "name": "Item 1", "description": "First item"},
            {"id": 2, "name": "Item 2", "description": "Second item"},
            {"id": 3, "name": "Item 3", "description": "Third item"},
        ]

        # Support optional filtering via query parameters
        name_filter = req.params.get('name')
        if name_filter:
            items = [item for item in items if name_filter.lower() in item["name"].lower()]

        return {
            "status": "success",
            "data": items,
            "count": len(items)
        }

    if action == "config":
        return {
            "status": "success",
            "data": {
                "api_version": "1.0.0",
                "environment": "development",
                "features": {
                    "authentication": True,
                    "notifications": True,
                    "dark_mode": True
                }
            }
        }

    # Default GET response
    return {
        "status": "success",
        "message": "SPA API is ready",
        "available_actions": ["health", "items", "config"],
        "method": "GET",
        "action": action or "none"
    }


def handle_post(req: func.HttpRequest, action: str) -> dict:
    """Handle POST requests."""
    logging.info(f"Handling POST request for action: {action}")

    # Parse request body
    try:
        request_body = req.get_json()
    except ValueError:
        request_body = None

    if not request_body:
        raise ValueError("Request body is required for POST requests and must be valid JSON.")

    if action == "items":
        # Validate required fields
        name = request_body.get("name")
        if not name:
            raise ValueError("Field 'name' is required to create an item.")

        new_item = {
            "id": 4,  # In a real app, this would be auto-generated
            "name": name,
            "description": request_body.get("description", ""),
        }

        return {
            "status": "success",
            "message": "Item created successfully",
            "data": new_item
        }

    if action == "contact":
        email = request_body.get("email")
        message = request_body.get("message")

        if not email or not message:
            raise ValueError("Fields 'email' and 'message' are required.")

        logging.info(f"Contact form submission from: {email}")

        return {
            "status": "success",
            "message": "Contact form submitted successfully",
            "data": {
                "email": email,
                "received": True
            }
        }

    return {
        "status": "success",
        "message": "POST request processed",
        "action": action or "none",
        "received_data": request_body
    }


def handle_put(req: func.HttpRequest, action: str) -> dict:
    """Handle PUT requests."""
    logging.info(f"Handling PUT request for action: {action}")

    try:
        request_body = req.get_json()
    except ValueError:
        request_body = None

    if not request_body:
        raise ValueError("Request body is required for PUT requests and must be valid JSON.")

    item_id = req.params.get('id')

    if action == "items":
        if not item_id:
            raise ValueError("Query parameter 'id' is required to update an item.")

        updated_item = {
            "id": int(item_id),
            "name": request_body.get("name", ""),
            "description": request_body.get("description", ""),
        }

        return {
            "status": "success",
            "message": f"Item {item_id} updated successfully",
            "data": updated_item
        }

    return {
        "status": "success",
        "message": "PUT request processed",
        "action": action or "none",
        "received_data": request_body
    }


def handle_delete(req: func.HttpRequest, action: str) -> dict:
    """Handle DELETE requests."""
    logging.info(f"Handling DELETE request for action: {action}")

    item_id = req.params.get('id')

    if action == "items":
        if not item_id:
            raise ValueError("Query parameter 'id' is required to delete an item.")

        return {
            "status": "success",
            "message": f"Item {item_id} deleted successfully",
            "data": {
                "id": int(item_id),
                "deleted": True
            }
        }

    return {
        "status": "success",
        "message": "DELETE request processed",
        "action": action or "none"
    }